VALUES
  ('diplomatic-9e854390-moex-00046', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-114-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司於X6年底並無列報無形資產，於X7年初取得乙公司控制權。合併當日，乙公司有正在執 行之三項可辨認且能可靠衡量之研發專案：', '["A專案：合併日公允價值$12,000；X7年間另投入$7,000，截至年底仍屬研究階段", "B專案：合併日公允價值$26,000；X7年間另投入$8,000，年末處於開發階段，未符合IAS38 第57段認列條件", "C專案：合併日公允價值$32,000；X7年間另投入$9,000，年末處於開發階段，已符合IAS38 第57段認列條件。 試問X7年底甲公司合併資產負債表應列示之無形資產合計為何？", "$70,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "fdd87a649633", "answer_pdf_sha1": "074507e641f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00047', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-114-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '下列四項中，有幾項不屬於投資性不動產？①目前尚未決定未來用途之建築物  ②出租予員工使', '["以融資租賃方式出租之不動產", "以營業租賃方式出租之辦公大樓", "1項", "2項"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "fdd87a649633", "answer_pdf_sha1": "074507e641f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00048', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-114-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '下列資產中，有幾項需要提列折舊？①已達可用狀態但尚未達經濟規模產出之設備  ②以公允價', '["以重估價模式衡量之建築物", "分類為待出售非流動資產的建 築物", "1項", "2項"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "fdd87a649633", "answer_pdf_sha1": "074507e641f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00049', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-114-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司自 X5 年起銷售一款新產品，提供兩年保固。依同業與本公司經驗，保固成本占銷貨收入 比率於出售後第一年估計為2.5%，出售後第二年估計為5.5%。X5與X6年度之銷貨與實際已支 付保固費用如下： X5年：銷貨$420,000；已發生保固支出$10,000 X6年：銷貨$560,000；已發生保固支出$22,000 試問截至X6年12月31日應列報之估計產品保固負債餘額為何？', '["$44,800", "$46,400", "$48,000", "$52,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "fdd87a649633", "answer_pdf_sha1": "074507e641f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00050', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-114-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'single_choice', '甲公司於X5年度的相關資料如下：本期稅後淨利$360,000；處分機器收現$240,000（其中包含出 售利益$80,000）；折舊費用$70,000；提列預期信用減損損失$30,000；應收帳款淨額增加$50,000。 請計算X5年度來自營業活動之現金流量為何？', '["$300,000", "$330,000", "$350,000", "$370,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "fdd87a649633", "answer_pdf_sha1": "074507e641f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00051', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-114-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '依憲法及增修條文規定，關於基本國策之敘述，下列何者錯誤？', '["國家應重視水資源之開發利用", "合作事業應受國家之獎勵與扶助", "國家應普設平民金融機構以救濟失業", "國家應保護科學技術以避免其外流"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "2bccfca1f9ac", "answer_pdf_sha1": "50e63616c79c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00052', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-114-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '依司法院大法官解釋意旨，下列敘述何者正確？', '["以行政規則限制電子遊藝場業之營業場所，合憲", "限制公職人員不得與其服務之機關為交易行為之規定，合憲", "要求一定規模以上之政府採購得標廠商進用原住民之規定，違憲", "限制藥師只能在一處執業的規定，合憲"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "2bccfca1f9ac", "answer_pdf_sha1": "50e63616c79c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00053', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-114-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '關於主權之概念，自16世紀至二次大戰前有各種理論。其中有關「政府僅係主權者的受僱人，若受 僱人不能符合其僱用人之意志，主權者有權將其解僱」為下列何者之主張？', '["君主主權論", "國民主權論", "國家主權論", "國會主權論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "2bccfca1f9ac", "answer_pdf_sha1": "50e63616c79c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00054', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-114-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '依司法院釋字第476號解釋有關毒品危害防制條例死刑及無期徒刑是否違憲之解釋意旨，生命權在我 國憲法是從何種憲法權利推導而出？', '["人身自由", "財產權", "訴訟權", "生存權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "2bccfca1f9ac", "answer_pdf_sha1": "50e63616c79c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00055', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-114-c655adf3', 'sub-diplomatic-9e854390-03', NULL, 'single_choice', '關於我國覆議制度，下列敘述何者最為正確？', '["覆議制度是內閣制的重要特徵", "依現行憲法增修條文，行政院對於立法院通過之重要政策變更之決議、法律案、預算案、條約案， 得提請覆議", "行政院得僅對於立法院議決法律案之部分法條提請覆議", "依現行憲法增修條文，覆議若經全體立法委員3分之2以上決議維持原案，行政院院長應接受"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "2bccfca1f9ac", "answer_pdf_sha1": "50e63616c79c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL)
